INSERT INTO facts (id, category, region, name, name_local, illustration_path, fact_sentence, active, created_at, updated_at)
VALUES
  ('flag_nigeria', 'flag', 'africa_west', 'Nigeria', NULL, 'flags/nigeria.svg', 'Nigeria is Africa''s most populous country and the continent''s largest economy by GDP.', true, now(), now()),
  ('flag_ethiopia', 'flag', 'africa_east', 'Ethiopia', NULL, 'flags/ethiopia.svg', 'Ethiopia is the only African country never colonized by a European power, and one of the world''s oldest continuous civilizations.', true, now(), now()),
  ('flag_kenya', 'flag', 'africa_east', 'Kenya', NULL, 'flags/kenya.svg', 'Kenya straddles the equator and is home to the Great Rift Valley, one of the most significant geological features on Earth.', true, now(), now()),
  ('flag_south_africa', 'flag', 'africa_south', 'South Africa', NULL, 'flags/south_africa.svg', 'South Africa is the only country in the world with three official capital cities: Pretoria, Cape Town, and Bloemfontein.', true, now(), now()),
  ('flag_ghana', 'flag', 'africa_west', 'Ghana', NULL, 'flags/ghana.svg', 'Ghana was the first sub-Saharan African country to gain independence from European colonial rule, in 1957.', true, now(), now()),
  ('flag_morocco', 'flag', 'africa_north', 'Morocco', NULL, 'flags/morocco.svg', 'Morocco is the only African country with coastlines on both the Atlantic Ocean and the Mediterranean Sea.', true, now(), now()),
  ('flag_tanzania', 'flag', 'africa_east', 'Tanzania', NULL, 'flags/tanzania.svg', 'Tanzania is home to Mount Kilimanjaro, the highest peak in Africa at 5,895 metres above sea level.', true, now(), now()),
  ('flag_botswana', 'flag', 'africa_south', 'Botswana', NULL, 'flags/botswana.svg', 'Botswana''s Okavango Delta is the world''s largest inland delta, flooding annually to create a unique freshwater oasis in the Kalahari Desert.', true, now(), now()),
  ('flag_senegal', 'flag', 'africa_west', 'Senegal', NULL, 'flags/senegal.svg', 'Senegal has never had a military coup since gaining independence, making it one of Africa''s most stable democracies.', true, now(), now()),
  ('flag_rwanda', 'flag', 'africa_east', 'Rwanda', NULL, 'flags/rwanda.svg', 'Rwanda has the highest proportion of women in parliament of any country in the world.', true, now(), now()),
  ('flag_japan', 'flag', 'asia_east', 'Japan', '日本'::text, 'flags/japan.svg', 'Japan is an archipelago of approximately 14,125 islands and has the world''s oldest continuous monarchy, dating back over 2,600 years.', true, now(), now()),
  ('flag_india', 'flag', 'asia_south', 'India', NULL, 'flags/india.svg', 'India is the world''s most populous country and is home to the largest film industry by number of films produced annually.', true, now(), now()),
  ('flag_vietnam', 'flag', 'asia_southeast', 'Vietnam', NULL, 'flags/vietnam.svg', 'Vietnam is the world''s second largest exporter of coffee, after Brazil, and one of the top rice exporters globally.', true, now(), now()),
  ('flag_philippines', 'flag', 'asia_southeast', 'Philippines', NULL, 'flags/philippines.svg', 'The Philippines is an archipelago of 7,641 islands and is one of the world''s greatest centres of marine biodiversity.', true, now(), now()),
  ('flag_thailand', 'flag', 'asia_southeast', 'Thailand', NULL, 'flags/thailand.svg', 'Thailand is the only Southeast Asian country never colonized by a European power, and its name means ''Land of the Free.''', true, now(), now()),
  ('flag_bangladesh', 'flag', 'asia_south', 'Bangladesh', NULL, 'flags/bangladesh.svg', 'Bangladesh is one of the world''s most densely populated large countries and the leading exporter of readymade garments.', true, now(), now()),
  ('flag_nepal', 'flag', 'asia_south', 'Nepal', NULL, 'flags/nepal.svg', 'Nepal is the only country in the world with a non-rectangular flag, and is home to eight of the world''s ten tallest mountains.', true, now(), now()),
  ('flag_mongolia', 'flag', 'asia_central', 'Mongolia', NULL, 'flags/mongolia.svg', 'Mongolia is the world''s largest landlocked country and has the lowest population density of any sovereign nation.', true, now(), now()),
  ('flag_brazil', 'flag', 'americas_south', 'Brazil', NULL, 'flags/brazil.svg', 'Brazil is the largest country in South America and covers nearly half the continent, making it the fifth largest country in the world.', true, now(), now()),
  ('flag_mexico', 'flag', 'americas_central', 'Mexico', NULL, 'flags/mexico.svg', 'Mexico City was built on the ruins of Tenochtitlán, the capital of the Aztec Empire, and sinks several centimetres each year.', true, now(), now()),
  ('flag_colombia', 'flag', 'americas_south', 'Colombia', NULL, 'flags/colombia.svg', 'Colombia is the only South American country with coastlines on both the Pacific Ocean and the Caribbean Sea.', true, now(), now()),
  ('flag_peru', 'flag', 'americas_south', 'Peru', NULL, 'flags/peru.svg', 'Peru was the centre of the Inca Empire, the largest empire in pre-Columbian America, and is one of the world''s most biodiverse countries.', true, now(), now()),
  ('flag_jamaica', 'flag', 'caribbean', 'Jamaica', NULL, 'flags/jamaica.svg', 'Jamaica is the birthplace of reggae music and the Rastafari movement, and its flag is one of the few that contains neither red, white, nor blue.', true, now(), now()),
  ('flag_new_zealand', 'flag', 'oceania_newzealand', 'New Zealand', NULL, 'flags/new_zealand.svg', 'New Zealand was the first self-governing country to grant women the right to vote in national elections, in 1893.', true, now(), now()),
  ('flag_fiji', 'flag', 'oceania_pacific', 'Fiji', NULL, 'flags/fiji.svg', 'Fiji is an archipelago of more than 330 islands and is considered one of the most isolated inhabited places on Earth.', true, now(), now()),
  ('flag_norway', 'flag', 'europe_north', 'Norway', NULL, 'flags/norway.svg', 'Norway contains the world''s longest road tunnel at 24.5 kilometres, and consistently ranks first in global human development indices.', true, now(), now()),
  ('flag_iceland', 'flag', 'europe_north', 'Iceland', NULL, 'flags/iceland.svg', 'Iceland is the most sparsely populated country in Europe and runs almost entirely on renewable energy from geothermal and hydroelectric sources.', true, now(), now()),
  ('flag_georgia', 'flag', 'asia_west', 'Georgia', NULL, 'flags/georgia.svg', 'Georgia''s Caucasus region is considered one of the cradles of winemaking, with evidence of viticulture dating back 8,000 years.', true, now(), now()),
  ('flag_bhutan', 'flag', 'asia_south', 'Bhutan', NULL, 'flags/bhutan.svg', 'Bhutan measures national happiness instead of GDP, making it the first country in the world to adopt Gross National Happiness as a development philosophy.', true, now(), now()),
  ('flag_cuba', 'flag', 'caribbean', 'Cuba', NULL, 'flags/cuba.svg', 'Cuba is the largest island in the Caribbean Sea and has one of the world''s highest literacy rates at over 99 percent.', true, now(), now()),
  ('landmark_pyramids_of_giza', 'landmark', 'africa_north', 'Pyramids of Giza', NULL, 'landmarks/pyramids_of_giza.svg', 'The Great Pyramid of Giza is the only surviving structure of the Seven Wonders of the Ancient World, built around 2560 BCE with over 2 million stone blocks.', true, now(), now()),
  ('landmark_kilimanjaro', 'landmark', 'africa_east', 'Mount Kilimanjaro', NULL, 'landmarks/kilimanjaro.svg', 'Mount Kilimanjaro is a free-standing volcanic massif rising 5,895 metres above sea level — the highest peak in Africa and the tallest free-standing mountain in the world.', true, now(), now()),
  ('landmark_victoria_falls', 'landmark', 'africa_south', 'Victoria Falls', NULL, 'landmarks/victoria_falls.svg', 'Victoria Falls, shared by Zimbabwe and Zambia, forms the world''s largest sheet of falling water, with a width of 1,708 metres and a height of 108 metres.', true, now(), now()),
  ('landmark_table_mountain', 'landmark', 'africa_south', 'Table Mountain', NULL, 'landmarks/table_mountain.svg', 'Table Mountain in Cape Town is one of the world''s oldest mountains, estimated to be 600 million years old, and hosts over 2,200 species of plants found nowhere else on Earth.', true, now(), now()),
  ('landmark_lalibela', 'landmark', 'africa_east', 'Rock-Hewn Churches of Lalibela', NULL, 'landmarks/lalibela.svg', 'The eleven churches of Lalibela in Ethiopia were carved entirely from solid red volcanic rock in the 12th century and are still used for worship today.', true, now(), now()),
  ('landmark_taj_mahal', 'landmark', 'asia_south', 'Taj Mahal', NULL, 'landmarks/taj_mahal.svg', 'The Taj Mahal was built by Mughal Emperor Shah Jahan in memory of his wife Mumtaz Mahal, and took over 20,000 workers approximately 22 years to complete.', true, now(), now()),
  ('landmark_angkor_wat', 'landmark', 'asia_southeast', 'Angkor Wat', NULL, 'landmarks/angkor_wat.svg', 'Angkor Wat in Cambodia is the world''s largest religious monument, covering 162.6 hectares, and was originally built as a Hindu temple before becoming Buddhist in the 14th century.', true, now(), now()),
  ('landmark_borobudur', 'landmark', 'asia_southeast', 'Borobudur', NULL, 'landmarks/borobudur.svg', 'Borobudur in Indonesia is the world''s largest Buddhist temple, built in the 9th century and decorated with 2,672 relief panels and 504 Buddha statues.', true, now(), now()),
  ('landmark_great_wall', 'landmark', 'asia_east', 'Great Wall of China', NULL, 'landmarks/great_wall.svg', 'The Great Wall of China stretches over 21,196 kilometres when all its branches are included, built across multiple dynasties over more than 2,000 years.', true, now(), now()),
  ('landmark_petra', 'landmark', 'asia_west', 'Petra', NULL, 'landmarks/petra.svg', 'Petra, Jordan''s ancient Nabataean city, was carved from rose-red sandstone cliffs around the 4th century BCE and remained unknown to the Western world until 1812.', true, now(), now()),
  ('landmark_mount_fuji', 'landmark', 'asia_east', 'Mount Fuji', NULL, 'landmarks/mount_fuji.svg', 'Mount Fuji is Japan''s highest peak at 3,776 metres, an active stratovolcano that last erupted in 1707, and a sacred site in Shinto tradition.', true, now(), now()),
  ('landmark_hagia_sophia', 'landmark', 'asia_west', 'Hagia Sophia', NULL, 'landmarks/hagia_sophia.svg', 'Hagia Sophia in Istanbul served as the world''s largest cathedral for nearly 1,000 years, then as a mosque, then a museum, and is once again a mosque today.', true, now(), now()),
  ('landmark_machu_picchu', 'landmark', 'americas_south', 'Machu Picchu', NULL, 'landmarks/machu_picchu.svg', 'Machu Picchu is a 15th-century Inca citadel set at 2,430 metres in the Peruvian Andes, built without mortar — its stones fit so precisely that a knife cannot slide between them.', true, now(), now()),
  ('landmark_chichen_itza', 'landmark', 'americas_central', 'Chichén Itzá', NULL, 'landmarks/chichen_itza.svg', 'Chichén Itzá was a major centre of Mayan civilisation; its pyramid El Castillo casts a serpent shadow down its staircase during each spring and autumn equinox.', true, now(), now()),
  ('landmark_grand_canyon', 'landmark', 'americas_north', 'Grand Canyon', NULL, 'landmarks/grand_canyon.svg', 'The Grand Canyon in Arizona is up to 1.8 kilometres deep, 446 kilometres long, and exposes nearly two billion years of Earth''s geological history in its layered rock walls.', true, now(), now()),
  ('landmark_iguazu_falls', 'landmark', 'americas_south', 'Iguazu Falls', NULL, 'landmarks/iguazu_falls.svg', 'Iguazu Falls on the Argentina–Brazil border is the world''s largest waterfall system, wider than Victoria Falls, with up to 275 individual drops spanning nearly 3 kilometres.', true, now(), now()),
  ('landmark_colosseum', 'landmark', 'europe_south', 'Colosseum', NULL, 'landmarks/colosseum.svg', 'The Colosseum in Rome could hold between 50,000 and 80,000 spectators for gladiatorial games, and was completed in 80 CE — a feat of engineering still studied today.', true, now(), now()),
  ('landmark_eiffel_tower', 'landmark', 'europe_west', 'Eiffel Tower', NULL, 'landmarks/eiffel_tower.svg', 'The Eiffel Tower was intended as a temporary structure for the 1889 World''s Fair and was nearly demolished in 1909; it is now the most visited paid monument in the world.', true, now(), now()),
  ('landmark_sagrada_familia', 'landmark', 'europe_south', 'Sagrada Família', NULL, 'landmarks/sagrada_familia.svg', 'Antoni Gaudí''s Sagrada Família basilica in Barcelona has been under continuous construction since 1882 and is expected to be completed around 2026.', true, now(), now()),
  ('landmark_uluru', 'landmark', 'oceania_australia', 'Uluru', NULL, 'landmarks/uluru.svg', 'Uluru is a sacred sandstone monolith in central Australia, 9.4 kilometres around its base, that changes colour dramatically at sunrise and sunset.', true, now(), now()),
  ('landmark_great_barrier_reef', 'landmark', 'oceania_australia', 'Great Barrier Reef', NULL, 'landmarks/great_barrier_reef.svg', 'The Great Barrier Reef is the world''s largest coral reef system, stretching 2,300 kilometres along Australia''s northeast coast and visible from outer space.', true, now(), now()),
  ('landmark_milford_sound', 'landmark', 'oceania_newzealand', 'Milford Sound', NULL, 'landmarks/milford_sound.svg', 'Milford Sound in New Zealand''s Fiordland was described by Rudyard Kipling as the eighth wonder of the world; its sheer cliffs rise over 1,200 metres directly from the sea.', true, now(), now()),
  ('landmark_pitons', 'landmark', 'caribbean', 'Pitons of St. Lucia', NULL, 'landmarks/pitons.svg', 'The Pitons are two volcanic spires rising from the Caribbean Sea on St. Lucia — Gros Piton at 798 metres and Petit Piton at 743 metres — designated a UNESCO World Heritage Site.', true, now(), now()),
  ('landmark_plitvice', 'landmark', 'europe_east', 'Plitvice Lakes', NULL, 'landmarks/plitvice.svg', 'Croatia''s Plitvice Lakes National Park contains 16 terraced lakes connected by waterfalls, their vivid turquoise colour created by minerals and microorganisms in the water.', true, now(), now()),
  ('landmark_stonehenge', 'landmark', 'europe_west', 'Stonehenge', NULL, 'landmarks/stonehenge.svg', 'Stonehenge in England was built in stages between 3000 and 1500 BCE; its largest stones weigh up to 25 tonnes and were transported from Wales, over 200 kilometres away.', true, now(), now()),
  ('constellation_orion', 'constellation', 'global', 'Orion', NULL, 'constellations/orion.svg', 'Orion is one of the most recognisable constellations in the night sky, visible from nearly every place on Earth, and has been used for navigation and calendar-keeping across cultures for thousands of years.', true, now(), now()),
  ('constellation_ursa_major', 'constellation', 'global', 'Ursa Major', NULL, 'constellations/ursa_major.svg', 'Ursa Major, the Great Bear, contains the Big Dipper asterism and is circumpolar — it never sets below the horizon for most of the northern hemisphere.', true, now(), now()),
  ('constellation_ursa_minor', 'constellation', 'global', 'Ursa Minor', NULL, 'constellations/ursa_minor.svg', 'Ursa Minor contains Polaris, the North Star, which sits almost exactly above Earth''s north pole and has guided navigators for centuries.', true, now(), now()),
  ('constellation_cassiopeia', 'constellation', 'global', 'Cassiopeia', NULL, 'constellations/cassiopeia.svg', 'Cassiopeia forms a distinctive W or M shape in the northern sky and is circumpolar, making it visible year-round from northern latitudes — named after a vain queen in Greek mythology.', true, now(), now()),
  ('constellation_crux', 'constellation', 'global', 'Crux (Southern Cross)', NULL, 'constellations/crux.svg', 'Crux, the Southern Cross, is the smallest of the 88 constellations and is used for navigation in the southern hemisphere the way Polaris is used in the north; it appears on the flags of five nations.', true, now(), now()),
  ('constellation_scorpius', 'constellation', 'global', 'Scorpius', NULL, 'constellations/scorpius.svg', 'Scorpius is one of the twelve zodiac constellations and contains Antares, a red supergiant star about 700 times the size of the Sun, whose name means ''rival of Mars'' due to its reddish hue.', true, now(), now()),
  ('constellation_leo', 'constellation', 'global', 'Leo', NULL, 'constellations/leo.svg', 'Leo the Lion contains Regulus, one of the brightest stars in the sky, located almost exactly on the ecliptic — the path the Sun appears to travel through the year.', true, now(), now()),
  ('constellation_gemini', 'constellation', 'global', 'Gemini', NULL, 'constellations/gemini.svg', 'Gemini is named after the twin brothers Castor and Pollux from Greek mythology; its two brightest stars share those names, with Pollux being the brighter and closer of the two.', true, now(), now()),
  ('constellation_pleiades', 'constellation', 'global', 'Pleiades (Seven Sisters)', NULL, 'constellations/pleiades.svg', 'The Pleiades star cluster is recognised independently by cultures worldwide: called Matariki in Māori tradition, Subaru in Japanese, and the Seven Sisters across dozens of Indigenous Australian nations.', true, now(), now()),
  ('constellation_centaurus', 'constellation', 'global', 'Centaurus', NULL, 'constellations/centaurus.svg', 'Centaurus contains Alpha Centauri, the nearest star system to our Sun at 4.37 light-years away, and Proxima Centauri, the single closest star to Earth.', true, now(), now()),
  ('constellation_lyra', 'constellation', 'global', 'Lyra', NULL, 'constellations/lyra.svg', 'Lyra contains Vega, the fifth brightest star in the night sky and one point of the Summer Triangle; due to Earth''s axial wobble, Vega will be the North Star again in about 12,000 years.', true, now(), now()),
  ('constellation_cygnus', 'constellation', 'global', 'Cygnus', NULL, 'constellations/cygnus.svg', 'Cygnus the Swan contains Deneb, one of the most luminous stars known in the Milky Way, and the Northern Cross asterism — used as a landmark in many Indigenous navigation traditions.', true, now(), now()),
  ('constellation_sagittarius', 'constellation', 'global', 'Sagittarius', NULL, 'constellations/sagittarius.svg', 'The centre of the Milky Way galaxy lies in the direction of Sagittarius, making this constellation the richest region of the sky for star clusters and nebulae.', true, now(), now()),
  ('constellation_taurus', 'constellation', 'global', 'Taurus', NULL, 'constellations/taurus.svg', 'Taurus contains both the Pleiades and the Hyades star clusters, and the Crab Nebula — the remnant of a supernova explosion observed and recorded by Chinese and Arab astronomers in 1054 CE.', true, now(), now()),
  ('constellation_aquila', 'constellation', 'global', 'Aquila', NULL, 'constellations/aquila.svg', 'Aquila the Eagle contains Altair, one of the closest stars visible to the naked eye at 16.7 light-years away, and is one point of the Summer Triangle asterism.', true, now(), now()),
  ('animal_quokka', 'animal', 'oceania_australia', 'Quokka', NULL, 'animals/quokka.svg', 'The quokka is a small marsupial native to Rottnest Island, Western Australia, and is often called ''the world''s happiest animal'' for the way its face naturally appears to smile.', true, now(), now()),
  ('animal_kakapo', 'animal', 'oceania_newzealand', 'Kākāpō', NULL, 'animals/kakapo.svg', 'The kākāpō is the world''s only flightless parrot and the heaviest parrot alive; critically endangered, its population was down to just 51 birds in 1995 before intensive conservation efforts began.', true, now(), now()),
  ('animal_capybara', 'animal', 'americas_south', 'Capybara', NULL, 'animals/capybara.svg', 'The capybara is the world''s largest rodent, native to South America, and is remarkably sociable — it is known to befriend almost any animal and is often seen napping alongside birds, monkeys, and caiman.', true, now(), now()),
  ('animal_axolotl', 'animal', 'americas_central', 'Axolotl', NULL, 'animals/axolotl.svg', 'The axolotl, native to lakes near Mexico City, can regenerate its own limbs, heart, and parts of its brain — a capability that makes it one of the most studied animals in biology.', true, now(), now()),
  ('animal_okapi', 'animal', 'africa_central', 'Okapi', NULL, 'animals/okapi.svg', 'The okapi of the Congo rainforest looks like a zebra-horse hybrid but is actually the only living relative of the giraffe, and was unknown to Western science until 1901.', true, now(), now()),
  ('animal_fennec_fox', 'animal', 'africa_north', 'Fennec Fox', NULL, 'animals/fennec_fox.svg', 'The fennec fox is the world''s smallest fox, native to the Sahara Desert, with ears up to 15 centimetres long that radiate excess body heat to keep it cool in extreme temperatures.', true, now(), now()),
  ('animal_snow_leopard', 'animal', 'asia_central', 'Snow Leopard', NULL, 'animals/snow_leopard.svg', 'Unlike other big cats, the snow leopard cannot roar; instead it makes a unique sound called a ''chuff,'' and its thick, spotted tail — nearly as long as its body — serves as a blanket in harsh mountain winters.', true, now(), now()),
  ('animal_pangolin', 'animal', 'asia_southeast', 'Pangolin', NULL, 'animals/pangolin.svg', 'The pangolin is the world''s most trafficked mammal; its scales, made of keratin, are used in traditional medicine, despite being identical in composition to human fingernails.', true, now(), now()),
  ('animal_narwhal', 'animal', 'polar', 'Narwhal', NULL, 'animals/narwhal.svg', 'The narwhal''s iconic ''tusk'' is actually a spiralling canine tooth that can grow up to 3 metres long and contains millions of nerve endings, making it a sensitive sensory organ.', true, now(), now()),
  ('animal_platypus', 'animal', 'oceania_australia', 'Platypus', NULL, 'animals/platypus.svg', 'The platypus is one of just five egg-laying mammals (monotremes) on Earth, the males are venomous, and it detects prey underwater using electroreceptors in its bill — making it one of nature''s strangest designs.', true, now(), now()),
  ('animal_shoebill', 'animal', 'africa_east', 'Shoebill', NULL, 'animals/shoebill.svg', 'The shoebill of central and east Africa can stand motionless for hours waiting for fish, and its prehistoric appearance — reminiscent of a dinosaur — has earned it the nickname ''whalehead.''', true, now(), now()),
  ('animal_red_panda', 'animal', 'asia_east', 'Red Panda', NULL, 'animals/red_panda.svg', 'Despite its name and diet of bamboo, the red panda is more closely related to raccoons and weasels than to giant pandas, and was the original animal called ''panda'' — decades before the giant panda was known in the West.', true, now(), now()),
  ('animal_maned_wolf', 'animal', 'americas_south', 'Maned Wolf', NULL, 'animals/maned_wolf.svg', 'The maned wolf is the tallest wild canid in South America and is not closely related to wolves or foxes; it is the sole species in its genus and smells strongly of skunk due to its distinctive scent marking.', true, now(), now()),
  ('animal_tuatara', 'animal', 'oceania_newzealand', 'Tuatara', NULL, 'animals/tuatara.svg', 'The tuatara of New Zealand has a third ''parietal eye'' on top of its head sensitive to light, is the last surviving member of an ancient reptile order, and can live over 100 years.', true, now(), now()),
  ('animal_harpy_eagle', 'animal', 'americas_south', 'Harpy Eagle', NULL, 'animals/harpy_eagle.svg', 'The harpy eagle is the largest raptor in the Americas, with talons the size of a grizzly bear''s claws; it is powerful enough to snatch prey nearly equal to its own body weight from the forest canopy.', true, now(), now()),
  ('animal_echidna', 'animal', 'oceania_australia', 'Echidna', NULL, 'animals/echidna.svg', 'The echidna is one of only five egg-laying mammals alive today, has no teeth and swallows food whole using a long sticky tongue, and has the lowest body temperature of any mammal.', true, now(), now()),
  ('animal_dugong', 'animal', 'asia_southeast', 'Dugong', NULL, 'animals/dugong.svg', 'The dugong, a large marine herbivore found in the Indo-Pacific, is thought to be the origin of mermaid legends; sailors who had been at sea for months mistook their distant silhouettes for half-human figures.', true, now(), now()),
  ('animal_secretary_bird', 'animal', 'africa_south', 'Secretary Bird', NULL, 'animals/secretary_bird.svg', 'The secretary bird is a large raptor that hunts on foot across African savannas, killing prey — including venomous snakes — by stomping with specialised, blunt-clawed feet at speeds that generate five times the force of gravity.', true, now(), now()),
  ('animal_gerenuk', 'animal', 'africa_east', 'Gerenuk', NULL, 'animals/gerenuk.svg', 'The gerenuk of east Africa is a long-necked antelope that stands entirely upright on its hind legs to browse high tree branches — a posture no other antelope achieves.', true, now(), now()),
  ('animal_komodo_dragon', 'animal', 'asia_southeast', 'Komodo Dragon', NULL, 'animals/komodo_dragon.svg', 'The Komodo dragon is the world''s largest lizard, capable of detecting carrion from up to 9.5 kilometres away, and can reproduce by parthenogenesis — females can produce offspring without a male.', true, now(), now()),
  ('geo_amazon_river', 'geography', 'americas_south', 'Amazon River', NULL, 'geography/amazon_river.svg', 'The Amazon River carries approximately 20 percent of all fresh water discharged into the world''s oceans and during its wet season expands to flood an area larger than France.', true, now(), now()),
  ('geo_nile_river', 'geography', 'africa_north', 'Nile River', NULL, 'geography/nile_river.svg', 'The Nile is the world''s longest river at approximately 6,650 kilometres, flowing northward through eleven countries before emptying into the Mediterranean Sea.', true, now(), now()),
  ('geo_sahara_desert', 'geography', 'africa_north', 'Sahara Desert', NULL, 'geography/sahara_desert.svg', 'The Sahara is the world''s largest hot desert at roughly 9 million square kilometres — comparable in size to China — and contains the highest sand dunes on Earth, some reaching 180 metres.', true, now(), now()),
  ('geo_himalayas', 'geography', 'asia_south', 'Himalayas', NULL, 'geography/himalayas.svg', 'The Himalayas are home to all fourteen peaks over 8,000 metres, including Mount Everest, and were formed when the Indian tectonic plate collided with the Eurasian plate approximately 50 million years ago.', true, now(), now()),
  ('geo_dead_sea', 'geography', 'asia_west', 'Dead Sea', NULL, 'geography/dead_sea.svg', 'The Dead Sea is the lowest point on Earth''s surface at 430 metres below sea level; its water is nearly ten times saltier than the ocean, allowing people to float effortlessly on its surface.', true, now(), now()),
  ('geo_lake_baikal', 'geography', 'europe_east', 'Lake Baikal', NULL, 'geography/lake_baikal.svg', 'Lake Baikal in Siberia is the world''s deepest lake at 1,642 metres and holds approximately 20 percent of Earth''s unfrozen fresh surface water — more than all of North America''s Great Lakes combined.', true, now(), now()),
  ('geo_amazon_rainforest', 'geography', 'americas_south', 'Amazon Rainforest', NULL, 'geography/amazon_rainforest.svg', 'The Amazon Rainforest spans nine countries, produces about 20 percent of Earth''s oxygen, and is home to roughly 10 percent of all species on the planet.', true, now(), now()),
  ('geo_atacama_desert', 'geography', 'americas_south', 'Atacama Desert', NULL, 'geography/atacama_desert.svg', 'The Atacama Desert in South America is the world''s driest non-polar desert; some weather stations there have never recorded rainfall, and parts of it resemble the surface of Mars.', true, now(), now()),
  ('geo_congo_river', 'geography', 'africa_central', 'Congo River', NULL, 'geography/congo_river.svg', 'The Congo River is the world''s deepest river, with sections exceeding 220 metres, and is the second largest river by water volume — forming the border between two countries that share its name.', true, now(), now()),
  ('geo_great_rift_valley', 'geography', 'africa_east', 'Great Rift Valley', NULL, 'geography/great_rift_valley.svg', 'The Great Rift Valley is a geological fracture stretching 6,000 kilometres from the Afar Triangle in Ethiopia to Mozambique; Africa is slowly splitting apart along this seam.', true, now(), now())
